from beeai import Agent
from pydantic import BaseModel, Field
from typing import Optional

class InvoiceData(BaseModel):
    invoice_number: str = Field(..., description="Unique invoice ID")
    date: str = Field(..., description="Invoice date")
    total_amount: float = Field(..., description="Total amount")
    vendor: Optional[str] = Field(None)

class ExtractionAgent(Agent):
    def __init__(self):
        super().__init__(
            model="granite-3.0",
            tools=[self.extract_invoice],
            memory_size_limit=1000
        )

    def extract_invoice(self, document_text: str) -> InvoiceData:
        prompt = f"""Extract invoice data from: {document_text}"""
        return self._call_llm_with_schema(prompt, InvoiceData)

def validate_extraction(data: InvoiceData) -> bool:
    required_fields = ['invoice_number', 'date', 'total_amount']
    missing = [f for f in required_fields if not getattr(data, f)]
    if missing:
        print(f'Missing fields: {missing}')
        return False
    if data.total_amount <= 0:
        print('Invalid total amount')
        return False
    return True

# Usage
for result in results:
    validated = validate_extraction(InvoiceData(**result))
    if validated:
        print('✓ Valid extraction')

from typing import List, Dict

class ExtractionProcessor:
    def __init__(self, agent: ExtractionAgent):
        self.agent = agent
        self.success_count = 0
        self.error_count = 0

    def process_batch(self, documents: List[str]) -> List[Dict]:
        results = []
        for i, doc in enumerate(documents):
            try:
                extraction = self.agent.extract_invoice(doc)
                if validate_extraction(extraction):
                    results.append({
                        'status': 'success',
                        'data': extraction.model_dump(),
                        'doc_index': i
                    })
                    self.success_count += 1
                else:
                    results.append({'status': 'validation_failed', 'doc_index': i})
            except Exception as e:
                results.append({'status': 'error', 'error': str(e), 'doc_index': i})
                self.error_count += 1
        return results

