from vex_sdk import VexClient
from beeai import AgentEvent

vex = VexClient(api_key="your-vex-key")

@vex.on_agent_event("beeai")
def handle_beeai_event(event: AgentEvent):
    if event.type == "tool_call":
        vex.validate_tool_call(
            tool_name=event.tool_name,
            params=event.params,
            risk_profile="medium"
        )
    elif event.type == "memory_update":
        vex.enforce_memory_limit(event.session_id, max_tokens=50000)

# Register with BeeAI agent
agent.add_event_listener(vex_event_handler)

@vex.guardrail("schema-compliance")
def validate_extraction_schema(data: dict, schema: type[BaseModel]):
    try:
        # Parse and validate
        parsed = schema(**data)

        # Completeness check
        required_fields = {f.name for f in schema.__fields__.values() 
                         if f.required}
        missing = required_fields - set(k for k, v in data.items() if v)

        if missing:
            vex.alert(f'Missing required fields: {missing}')
            return False

        # Type consistency
        for field, value in data.items():
            field_type = schema.__fields__[field].type_
            if not isinstance(value, field_type):
                vex.alert(f'Type mismatch: {field} expected {field_type}')
                return False

        return True
    except Exception as e:
        vex.alert(f'Schema validation failed: {e}')
        return False

# Usage in pipeline
if validate_extraction_schema(result, InvoiceData):
    print('Schema compliant')

@vex.guardrail("extraction-quality")
def validate_field_accuracy(data: InvoiceData, context: str):
    # Amount reasonableness check
    if data.total_amount > 1000000:
        vex.flag('suspicious_amount', data.total_amount)
        return False

    # Date format validation
    from datetime import datetime
    try:
        datetime.strptime(data.date, '%Y-%m-%d')
    except:
        vex.flag('invalid_date_format', data.date)
        return False

    return True

@vex.guardrail("memory-protection")
def check_memory_usage(session):
    memory_usage = session.get_memory_usage()
    if memory_usage > 45000:
        session.truncate_memory(keep_last_n=50)
        vex.log('memory_truncated', {'tokens_saved': memory_usage - 40000})

# Integrate into agent lifecycle
agent.on_before_tool_call(validate_extraction_schema)
agent.on_memory_update(check_memory_usage)
